import {Sparkles} from "lucide-react";
import React from "react";

function DataEntityContainer({ theme = 'pink', children, title = '可爱参数面板', subtitle = '调整你的专属设置 ♡' }) {
    const themes = {
        pink: 'from-pink-100 to-purple-100',
        blue: 'from-blue-100 to-cyan-100',
        peach: 'from-orange-100 to-pink-100'
    };

    return (
        <div className="min-h-screen flex items-center justify-center p-4 bg-gradient-to-br from-pink-50 via-purple-50 to-blue-50">
            <div className={`w-full max-w-md bg-gradient-to-br ${themes[theme]} rounded-3xl shadow-2xl p-6 space-y-4 border-4 border-white/50`}>
                <div className="text-center mb-6">
                    <div className="flex items-center justify-center gap-2 mb-2">
                        <Sparkles className="text-pink-500" size={24} />
                        <h2 className="text-2xl font-bold bg-gradient-to-r from-pink-500 to-purple-500 bg-clip-text text-transparent">
                            {title}
                        </h2>
                        <Sparkles className="text-purple-500" size={24} />
                    </div>
                    <p className="text-sm text-gray-600">{subtitle}</p>
                    <p className="text-xs text-pink-400 mt-1">点击图标可更换图标和颜色哦 ~</p>
                </div>

                {children}

                <div className="text-center pt-4">
                    <p className="text-xs text-gray-500">♡ 愿你每天都充满快乐 ♡</p>
                </div>
            </div>
        </div>
    );
}

export default DataEntityContainer
